11	const ITEM_BASE_PRICES: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const MAIN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion"]);
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = { type: string; enchantment?: number; cursed?: boolean };
24	type Customer = { yearsWithMHPCO?: number };
25	type Scenario = {
26	  customer?: Customer;
27	  steps: { op: string; items: Item[] }[];
28	};
