30	function countItemsByType(items: Item[]): Map<string, number> {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	}
37	
38	function blockDiscountFor(type: string, count: number): number {
39	  const isComponent = COMPONENT_TYPES.has(type);
40	  const formsBlock = count === BLOCK_SIZE;
41	  return isComponent && formsBlock ? BLOCK_OF_THREE_DISCOUNT : 0;
42	}
43	
44	function basePremiumForGroup(type: string, count: number): number {
45	  return count * ITEM_BASE_PRICES[type] - blockDiscountFor(type, count);
46	}
47	
48	function computePolicyBase(items: Item[]): number {
49	  const itemCountsByType = countItemsByType(items);
50	  let basePremium = 0;
51	  for (const [type, count] of itemCountsByType.entries()) {
52	    basePremium += basePremiumForGroup(type, count);
53	  }
54	  return basePremium;
55	}
56	
57	function sumItemSurcharge(
58	  items: Item[],
59	  rate: number,
60	  applies: (item: Item) => boolean,
61	): number {
62	  return items
63	    .filter(applies)
64	    .reduce((sum, item) => sum + ITEM_BASE_PRICES[item.type] * rate, 0);
65	}
66	
67	function computeFirstInsuranceSurcharge(items: Item[]): number {
68	  return sumItemSurcharge(items, FIRST_INSURANCE_RATE, (item) =>
69	    MAIN_ITEM_TYPES.has(item.type),
70	  );
71	}
72	
73	function computeHighEnchantmentSurcharge(items: Item[]): number {
74	  return sumItemSurcharge(
75	    items,
76	    HIGH_ENCHANTMENT_RATE,
77	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
78	  );
79	}
80	
81	function computeCursedSurcharge(items: Item[]): number {
82	  return sumItemSurcharge(items, CURSED_RATE, (item) => item.cursed === true);
83	}
84	
85	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
86	  const years = customer.yearsWithMHPCO ?? 0;
87	  if (years >= LOYALTY_YEARS_THRESHOLD) {
88	    return policyBase * LOYALTY_DISCOUNT_RATE;
89	  }
90	  return 0;
91	}
92	
93	export function runScenario(scenario: unknown): unknown {
94	  const s = scenario as Scenario;
95	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
96	  const items = s.steps[0].items;
97	
98	  const policyBase = computePolicyBase(items);
99	  const highEnchantmentSurcharge = computeHighEnchantmentSurcharge(items);
100	  const cursedSurcharge = computeCursedSurcharge(items);
101	  const firstInsuranceSurcharge = computeFirstInsuranceSurcharge(items);
102	  const loyaltyDiscount = computeLoyaltyDiscount(policyBase, customer);
103	
104	  const premium =
105	    policyBase +
106	    highEnchantmentSurcharge +
107	    cursedSurcharge +
108	    firstInsuranceSurcharge -
109	    loyaltyDiscount +
110	    PROCESSING_FEE;
111	  return { results: [{ premium }] };
112	}
