export function runScenario(scenario: unknown): unknown {
  const s = scenario as Scenario;
  const customer = s.customer ?? { yearsWithMHPCO: 0 };

  const results: { premium: number }[] = [];
  let quoteStepIndex = 0;
  for (const step of s.steps) {
    const items = step.items;
    const policyBase = computePolicyBase(items);
    const highEnchantmentSurcharge = computeHighEnchantmentSurcharge(items);
    const cursedSurcharge = computeCursedSurcharge(items);
    const firstInsuranceSurcharge = computeFirstInsuranceSurcharge(items);
    const loyaltyDiscount = computeLoyaltyDiscount(policyBase, customer);
    const followUpDiscount =
      quoteStepIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;

    const premium =
      policyBase +
      highEnchantmentSurcharge +
      cursedSurcharge +
      firstInsuranceSurcharge -
      loyaltyDiscount -
      followUpDiscount +
      PROCESSING_FEE;
    results.push({ premium: Math.ceil(premium) });
    quoteStepIndex++;
  }
  return { results };
}

